// MARK: - Encryption Service

final class EncryptionService {
    
    static let shared = EncryptionService()
    private init() {}
    
    enum EncryptionError: Error, LocalizedError {
        case keyGenerationFailed
        case encryptionFailed
        case decryptionFailed
        case invalidData
        case keychainError(OSStatus)
        case hashMismatch
        
        var errorDescription: String? {
            switch self {
            case .keyGenerationFailed: return "Failed to generate encryption key"
            case .encryptionFailed: return "Encryption failed"
            case .decryptionFailed: return "Decryption failed"
            case .invalidData: return "Invalid data"
            case .keychainError(let status): return "Keychain error: \(status)"
            case .hashMismatch: return "Data integrity check failed"
            }
        }
    }
    
    private let keychainService = "com.banking.secureapp.keys"
    private let masterKeyTag = "com.banking.secureapp.masterkey"
    
    // MARK: - Key Management
    
    func getOrCreateMasterKey() throws -> SymmetricKey {
        if let existingKeyData = try? loadKeyFromKeychain(tag: masterKeyTag) {
            return SymmetricKey(data: existingKeyData)
        }
        
        let newKey = SymmetricKey(size: .bits256)
        let keyData = newKey.withUnsafeBytes { Data($0) }
        try saveKeyToKeychain(keyData: keyData, tag: masterKeyTag)
        return newKey
    }
    
    private func saveKeyToKeychain(keyData: Data, tag: String) throws {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainService,
            kSecAttrAccount as String: tag,
            kSecValueData as String: keyData,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        
        // Delete existing
        SecItemDelete(query as CFDictionary)
        
        let status = SecItemAdd(query as CFDictionary, nil)
        guard status == errSecSuccess else {
            throw EncryptionError.keychainError(status)
        }
    }
    
    private func loadKeyFromKeychain(tag: String) throws -> Data {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainService,
            kSecAttrAccount as String: tag,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess, let data = result as? Data else {
            throw EncryptionError.keychainError(status)
        }
        
        return data
    }
    
    // MARK: - AES-GCM Encryption
    
    func encrypt(data: Data) throws -> Data {
        let key = try getOrCreateMasterKey()
        
        guard let sealedBox = try? AES.GCM.seal(data, using: key) else {
            throw EncryptionError.encryptionFailed
        }
        
        guard let combined = sealedBox.combined else {
            throw EncryptionError.encryptionFailed
        }
        
        return combined
    }
    
    func decrypt(data: Data) throws -> Data {
        let key = try getOrCreateMasterKey()
        
        guard let sealedBox = try? AES.GCM.SealedBox(combined: data) else {
            throw EncryptionError.invalidData
        }
        
        guard let decryptedData = try? AES.GCM.open(sealedBox, using: key) else {
            throw EncryptionError.decryptionFailed
        }
        
        return decryptedData
    }
    
    // MARK: - Hashing
    
    func sha256Hash(data: Data) -> String {
        let hash = SHA256.hash(data: data)
        return hash.compactMap { String(format: "%02x", $0) }.joined()
    }
    
    func hmac(data: Data, key: SymmetricKey) -> Data {
        let authCode = HMAC<SHA256>.authenticationCode(for: data, using: key)
        return Data(authCode)
    }
    
    func verifyHMAC(data: Data, mac: Data, key: SymmetricKey) -> Bool {
        let authCode = HMAC<SHA256>.authenticationCode(for: data, using: key)
        return Data(authCode) == mac
    }
    
    // MARK: - Encrypt Strings
    
    func encryptString(_ string: String) throws -> Data {
        guard let data = string.data(using: .utf8) else {
            throw EncryptionError.invalidData
        }
        return try encrypt(data: data)
    }
    
    func decryptString(data: Data) throws -> String {
        let decryptedData = try decrypt(data: data)
        guard let string = String(data: decryptedData, encoding: .utf8) else {
            throw EncryptionError.invalidData
        }
        return string
    }
}

// MARK: - Secure Storage

final class SecureStorage {
    
    static let shared = SecureStorage()
    private let encryption = EncryptionService.shared
    private let fileManager = FileManager.default
    
    private var secureDirectory: URL {
        let documentsPath = fileManager.urls(for: .documentDirectory, in: .userDomainMask)[0]
        let securePath = documentsPath.appendingPathComponent(".secure_data", isDirectory: true)
        
        if !fileManager.fileExists(atPath: securePath.path) {
            try? fileManager.createDirectory(at: securePath, withIntermediateDirectories: true)
            // Exclude from backups
            var resourceValues = URLResourceValues()
            resourceValues.isExcludedFromBackup = true
            var mutablePath = securePath
            try? mutablePath.setResourceValues(resourceValues)
        }
        
        return securePath
    }
    
    private init() {}
    
    func save<T: Codable>(_ object: T, forKey key: String) throws {
        let data = try JSONEncoder().encode(object)
        let encryptedData = try encryption.encrypt(data: data)
        let filePath = secureDirectory.appendingPathComponent(encryption.sha256Hash(data: key.data(using: .utf8)!))
        try encryptedData.write(to: filePath, options: .completeFileProtection)
    }
    
    func load<T: Codable>(forKey key: String, type: T.Type) throws -> T {
        let filePath = secureDirectory.appendingPathComponent(encryption.sha256Hash(data: key.data(using: .utf8)!))
        let encryptedData = try Data(contentsOf: filePath)
        let decryptedData = try encryption.decrypt(data: encryptedData)
        return try JSONDecoder().decode(T.self, from: decryptedData)
    }
    
    func delete(forKey key: String) throws {
        let filePath = secureDirectory.appendingPathComponent(encryption.sha256Hash(data: key.data(using: .utf8)!))
        try fileManager.removeItem(at: filePath)
    }
    
    func exists(forKey key: String) -> Bool {
        let filePath = secureDirectory.appendingPathComponent(encryption.sha256Hash(data: key.data(using: .utf8)!))
        return fileManager.fileExists(atPath: filePath.path)
    }
}

// MARK: - Data Models

struct Account: Codable, Identifiable {
    let id: String
    let accountNumber: String
    let accountType: AccountType
    var balance: Decimal
    let currency: String
    let ownerName: String
    let createdAt: Date
    var lastUpdated: Date
    
    enum AccountType: String, Codable {
        case checking = "Checking"
        case savings = "Savings"
        case credit = "Credit"
        case investment = "Investment"
    }
    
    var maskedAccountNumber: String {
        let lastFour = String(accountNumber.suffix(4))
        return "****\(lastFour)"
    }
    
    var formattedBalance: String {
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        formatter.currencyCode = currency
        return formatter.string(from: balance as NSDecimalNumber) ?? "$0.00"
    }
}

struct Transaction: Codable, Identifiable {
    let id: String
    let accountId: String
    let type: TransactionType
    let amount: Decimal
    let currency: String
    let description: String
    let merchantName: String?
    let category: TransactionCategory
    let status: TransactionStatus
    let timestamp: Date
    let referenceNumber: String
    let fromAccountId: String?
    let toAccountId: String?
    let metadata: [String: String]?
    
    enum TransactionType: String, Codable {
        case debit = "Debit"
        case credit = "Credit"
        case transfer = "Transfer"
        case payment = "Payment"
        case refund = "Refund"
        case fee = "Fee"
    }
    
    enum TransactionCategory: String, Codable {
        case groceries = "Groceries"
        case dining = "Dining"
        case transportation = "Transportation"
        case utilities = "Utilities"
        case entertainment = "Entertainment"
        case healthcare = "Healthcare"
        case shopping = "Shopping"
        case transfer = "Transfer"
        case income = "Income"
        case other = "Other"
    }
    
    enum TransactionStatus: String, Codable {
        case pending = "Pending"
        case completed = "Completed"
        case failed = "Failed"
        case cancelled = "Cancelled"
        case reversed = "Reversed"
    }
    
    var formattedAmount: String {
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        formatter.currencyCode = currency
        let prefix = type == .credit || type == .refund ? "+" : "-"
        return "\(prefix)\(formatter.string(from: amount as NSDecimalNumber) ?? "$0.00")"
    }
    
    var formattedDate: String {
        let formatter = DateFormatter()
        formatter.dateStyle = .medium
        formatter.timeStyle = .short
        return formatter.string(from: timestamp)
    }
}

struct TransferRequest: Codable {
    let fromAccountId: String
    let toAccountId: String
    let amount: Decimal
    let currency: String
    let description: String
    let scheduledDate: Date?
    
    func validate() -> [ValidationError] {
        var errors: [ValidationError] = []
        
        if fromAccountId.isEmpty {
            errors.append(.emptyField("Source account"))
        }
        if toAccountId.isEmpty {
            errors.append(.emptyField("Destination account"))
        }
        if fromAccountId == toAccountId {
            errors.append(.sameAccount)
        }
        if amount <= 0 {
            errors.append(.invalidAmount)
        }
        if amount > 50000 {
            errors.append(.exceedsLimit)
        }
        if description.isEmpty {
            errors.append(.emptyField("Description"))
        }
        if let scheduled = scheduledDate, scheduled < Date() {
            errors.append(.pastDate)
        }
        
        return errors
    }
    
    enum ValidationError: Error, LocalizedError {
        case emptyField(String)
        case sameAccount
        case invalidAmount
        case exceedsLimit
        case pastDate
        
        var errorDescription: String? {
            switch self {
            case .emptyField(let field): return "\(field) is required"
            case .sameAccount: return "Source and destination accounts must be different"
            case .invalidAmount: return "Amount must be greater than zero"
            case .exceedsLimit: return "Amount exceeds transfer limit of $50,000"
            case .pastDate: return "Scheduled date cannot be in the past"
            }
        }
    }
}

// MARK: - Audit Logger

final class AuditLogger {
    
    static let shared = AuditLogger()
    private let secureStorage = SecureStorage.shared
    private let encryption = EncryptionService.shared
    private var logBuffer: [AuditEntry] = []
    private let queue = DispatchQueue(label: "com.banking.auditlog", qos: .utility)
    
    struct AuditEntry: Codable {
        let id: String
        let timestamp: Date
        let action: String
        let details: String
        let userId: String?
        let ipAddress: String?
        let deviceInfo: String
        let riskLevel: String
        let integrityStatus: String
    }
    
    private init() {}
    
    func log(action: String, details: String, userId: String? = nil, riskLevel: String = "normal") {
        queue.async { [weak self] in
            let entry = AuditEntry(
                id: UUID().uuidString,
                timestamp: Date(),
                action: action,
                details: details,
                userId: userId,
                ipAddress: nil,
                deviceInfo: UIDevice.current.model,
                riskLevel: riskLevel,
                integrityStatus: DeviceIntegrityChecker.shared.performFullIntegrityCheck().isCompromised ? "compromised" : "clean"
            )
            
            self?.logBuffer.append(entry)
            
            if (self?.logBuffer.count ?? 0) >= 50 {
                self?.flushLogs()
            }
        }
    }
    
    func flushLogs() {
        queue.async { [weak self] in
            guard let self = self, !self.logBuffer.isEmpty else { return }
            
            do {
                var existingLogs: [AuditEntry] = []
                if let loaded = try? self.secureStorage.load(forKey: "audit_logs", type: [AuditEntry].self) {
                    existingLogs = loaded
                }
                existingLogs.append(contentsOf: self.logBuffer)
                
                // Keep only last 1000 entries
                if existingLogs.count > 1000 {
                    existingLogs = Array(existingLogs.suffix(1000))
                }
                
                try self.secureStorage.save(existingLogs, forKey: "audit_logs")
                self.logBuffer.removeAll()
            } catch {
                print("Failed to flush audit logs: \(error)")
            }
        }
    }
}

// MARK: - Biometric Authentication

final class BiometricAuthService {
    
    static let shared = BiometricAuthService()
    private init() {}
    
    enum BiometricError: Error, LocalizedError {
        case notAvailable
        case authenticationFailed
        case userCancelled
        case systemCancelled
        case passcodeNotSet
        case biometryLockout
        case unknown(Error)
        
        var errorDescription: String? {
            switch self {
            case .notAvailable: return "Biometric authentication is not available"
            case .authenticationFailed: return "Authentication failed"
            case .userCancelled: return "Authentication was cancelled"
            case .systemCancelled: return "Authentication was cancelled by the system"
            case .passcodeNotSet: return "Device passcode is not set"
            case .biometryLockout: return "Biometric authentication is locked out"
            case .unknown(let error): return error.localizedDescription
            }
        }
    }
    
    var isBiometricAvailable: Bool {
        let context = LAContext()
        var error: NSError?
        return context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error)
    }
    
    var biometricType: String {
        let context = LAContext()
        var error: NSError?
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            return "None"
        }
        
        switch context.biometryType {
        case .faceID: return "Face ID"
        case .touchID: return "Touch ID"
        case .opticID: return "Optic ID"
        @unknown default: return "Biometric"
        }
    }
    
    func authenticate(reason: String, completion: @escaping (Result<Bool, BiometricError>) -> Void) {
        let context = LAContext()
        context.localizedCancelTitle = "Cancel"
        context.localizedFallbackTitle = "Use Passcode"
        
        var error: NSError?
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            DispatchQueue.main.async {
                if let error = error {
                    switch error.code {
                    case LAError.biometryNotAvailable.rawValue:
                        completion(.failure(.notAvailable))
                    case LAError.passcodeNotSet.rawValue:
                        completion(.failure(.passcodeNotSet))
                    case LAError.biometryLockout.rawValue:
                        completion(.failure(.biometryLockout))
                    default:
                        completion(.failure(.unknown(error)))
                    }
                } else {
                    completion(.failure(.notAvailable))
                }
            }
            return
        }
        
        context.evaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, localizedReason: reason) { success, error in
            DispatchQueue.main.async {
                if success {
                    AuditLogger.shared.log(action: "biometric_auth", details: "Biometric authentication successful")
                    completion(.success(true))
                } else if let error = error as? LAError {
                    AuditLogger.shared.log(action: "biometric_auth_failed", details: "Error: \(error.localizedDescription)", riskLevel: "elevated")
                    switch error.code {
                    case .userCancel:
                        completion(.failure(.userCancelled))
                    case .systemCancel:
                        completion(.failure(.systemCancelled))
                    case .authenticationFailed:
                        completion(.failure(.authenticationFailed))
                    default:
                        completion(.failure(.unknown(error)))
                    }
                } else {
                    completion(.failure(.authenticationFailed))
                }
            }
        }
    }
}

// MARK: - Network Security

final class SecureNetworkService {
    
    static let shared = SecureNetworkService()
    
    private let session: URLSession
    private let encryption = EncryptionService.shared
    private let baseURL = "https://api.securebanking.example.com/v1"
    
    private init() {
        let config = URLSessionConfiguration.ephemeral
        config.tlsMinimumSupportedProtocolVersion = .TLSv12
        config.httpAdditionalHeaders = [
            "Content-Type": "application/json",
            "X-App-Version": Bundle.main.infoDictionary?["CFBundleShortVersionString"] as? String ?? "1.0",
            "X-Platform": "iOS"
        ]
        config.timeoutIntervalForRequest = 30
        config.timeoutIntervalForResource = 60
        config.urlCache = nil
        config.requestCachePolicy = .reloadIgnoringLocalAndRemoteCacheData
        
        let delegate = SSLPinningDelegate()
        session = URLSession(configuration: config, delegate: delegate, delegateQueue: nil)
    }
    
    enum NetworkError: Error, LocalizedError {
        case invalidURL
        case noData
        case decodingError
        case serverError(Int)
        case networkError(Error)
        case sslPinningFailed
        case rateLimited
        case unauthorized
        
        var errorDescription: String? {
            switch self {
            case .invalidURL: return "Invalid URL"
            case .noData: return "No data received"
            case .decodingError: return "Failed to decode response"
            case .serverError(let code): return "Server error: \(code)"
            case .networkError(let error): return error.localizedDescription
            case .sslPinningFailed: return "SSL certificate verification failed"
            case .rateLimited: return "Too many requests. Please try again later."
            case .unauthorized: return "Session expired. Please log in again."
            }
        }
    }
    
    func request<T: Decodable>(
        endpoint: String,
        method: String = "GET",
        body: Data? = nil,
        responseType: T.Type
    ) async throws -> T {
        guard let url = URL(string: "\(baseURL)/\(endpoint)") else {
            throw NetworkError.invalidURL
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = method
        request.httpBody = body
        
        // Add request signing
        let timestamp = String(Int(Date().timeIntervalSince1970))
        request.addValue(timestamp, forHTTPHeaderField: "X-Timestamp")
        
        if let body = body {
            let bodyHash = encryption.sha256Hash(data: body)
            request.addValue(bodyHash, forHTTPHeaderField: "X-Body-Hash")
        }
        
        // Add device integrity header
        let integrity = DeviceIntegrityChecker.shared.performFullIntegrityCheck()
        request.addValue(integrity.isCompromised ? "0" : "1", forHTTPHeaderField: "X-Device-Integrity")
        
        let (data, response) = try await session.data(for: request)
        
        guard let httpResponse = response as? HTTPURLResponse else {
            throw NetworkError.noData
        }
        
        switch httpResponse.statusCode {
        case 200...299:
            break
        case 401:
            throw NetworkError.unauthorized
        case 429:
            throw NetworkError.rateLimited
        default:
            throw NetworkError.serverError(httpResponse.statusCode)
        }
        
        do {
            let decoder = JSONDecoder()
            decoder.dateDecodingStrategy = .iso8601
            return try decoder.decode(T.self, from: data)
        } catch {
            throw NetworkError.decodingError
        }
    }
}

// MARK: - SSL Pinning Delegate

final class SSLPinningDelegate: NSObject, URLSessionDelegate {
    
    // SHA256 hashes of the expected certificate public keys
    private let pinnedPublicKeyHashes: Set<String> = [
        "BBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBB=",  // Primary
        "CCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCC="   // Backup
    ]
    
    func urlSession(
        _ session: URLSession,
        didReceive challenge: URLAuthenticationChallenge,
        completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void
    ) {
        guard challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust,
              let serverTrust = challenge.protectionSpace.serverTrust else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            AuditLogger.shared.log(action: "ssl_pinning_failed", details: "No server trust", riskLevel: "critical")
            return
        }
        
        // Evaluate the server trust
        var error: CFError?
        let isValid = SecTrustEvaluateWithError(serverTrust, &error)
        
        guard isValid else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            AuditLogger.shared.log(action: "ssl_pinning_failed", details: "Trust evaluation failed", riskLevel: "critical")
            return
        }
        
        // Check certificate chain for pinned keys
        let certificateCount = SecTrustGetCertificateCount(serverTrust)
        var foundPinnedKey = false
        
        for i in 0..<certificateCount {
            guard let certificate = SecTrustCopyCertificateChain(serverTrust)?[i] as? SecCertificate else {
                continue
            }
            
            if let publicKey = SecCertificateCopyKey(certificate),
               let publicKeyData = SecKeyCopyExternalRepresentation(publicKey, nil) as Data? {
                let hash = SHA256.hash(data: publicKeyData)
                let hashString = Data(hash).base64EncodedString()
                
                if pinnedPublicKeyHashes.contains(hashString) {
                    foundPinnedKey = true
                    break
                }
            }
        }
        
        if foundPinnedKey {
            completionHandler(.useCredential, URLCredential(trust: serverTrust))
        } else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            AuditLogger.shared.log(action: "ssl_pinning_failed", details: "No matching pinned key found", riskLevel: "critical")
        }
    }
}

// MARK: - Transaction Processor

final class TransactionProcessor {
    
    static let shared = TransactionProcessor()
    
    private let encryption = EncryptionService.shared
    private let secureStorage = SecureStorage.shared
    private let auditLogger = AuditLogger.shared
    private let networkService = SecureNetworkService.shared
    
    private let transactionQueue = DispatchQueue(label: "com.banking.transactions", qos: .userInitiated)
    private let rateLimiter = RateLimiter(maxRequests: 10, timeWindow: 60)
    
    enum TransactionError: Error, LocalizedError {
        case insufficientFunds
        case invalidAccount
        case transactionLimitExceeded
        case duplicateTransaction
        case processingError(String)
        case deviceCompromised
        case rateLimited
        case validationFailed([String])
        case authenticationRequired
        
        var errorDescription: String? {
            switch self {
            case .insufficientFunds: return "Insufficient funds"
            case .invalidAccount: return "Invalid account"
            case .transactionLimitExceeded: return "Transaction limit exceeded"
            case .duplicateTransaction: return "Duplicate transaction detected"
            case .processingError(let msg): return "Processing error: \(msg)"
            case .deviceCompromised: return "Transaction blocked: Device integrity check failed"
            case .rateLimited: return "Too many transactions. Please wait."
            case .validationFailed(let errors): return errors.joined(separator: "\n")
            case .authenticationRequired: return "Authentication required for this transaction"
            }
        }
    }
    
    private init() {}
    
    // MARK: - Process Transfer
    
    func processTransfer(
        request: TransferRequest,
        authenticated: Bool = false,
        completion: @escaping (Result<Transaction, TransactionError>) -> Void
    ) {
        // Defense-in-depth: Check device integrity before processing
        let integrityResult = DeviceIntegrityChecker.shared.performFullIntegrityCheck()
        if integrityResult.riskLevel >= .high {
            auditLogger.log(
                action: "transaction_blocked",
                details: "Device integrity check failed: \(integrityResult.threats.map { $0.rawValue })",
                riskLevel: "critical"
            )
            completion(.failure(.deviceCompromised))
            return
        }
        
        // Rate limiting
        guard rateLimiter.allowRequest() else {
            auditLogger.log(action: "rate_limited", details: "Transfer rate limited", riskLevel: "elevated")
            completion(.failure(.rateLimited))
            return
        }
        
        // Validate request
        let validationErrors = request.validate()
        if !validationErrors.isEmpty {
            completion(.failure(.validationFailed(validationErrors.map { $0.localizedDescription })))
            return
        }
        
        // Require authentication for large transfers
        if request.amount > 1000 && !authenticated {
            completion(.failure(.authenticationRequired))
            return
        }
        
        transactionQueue.async { [weak self] in
            guard let self = self else { return }
            
            // Check for duplicate transactions
            if self.isDuplicateTransaction(request: request) {
                self.auditLogger.log(action: "duplicate_transaction", details: "Duplicate transfer detected", riskLevel: "elevated")
                DispatchQueue.main.async {
                    completion(.failure(.duplicateTransaction))
                }
                return
            }
            
            // Load accounts
            guard var fromAccount = try? self.secureStorage.load(forKey: "account_\(request.fromAccountId)", type: Account.self),
                  var toAccount = try? self.secureStorage.load(forKey: "account_\(request.toAccountId)", type: Account.self) else {
                DispatchQueue.main.async {
                    completion(.failure(.invalidAccount))
                }
                return
            }
            
            // Check sufficient funds
            guard fromAccount.balance >= request.amount else {
                self.auditLogger.log(
                    action: "insufficient_funds",
                    details: "Account \(fromAccount.maskedAccountNumber) balance: \(fromAccount.balance), requested: \(request.amount)",
                    riskLevel: "normal"
                )
                DispatchQueue.main.async {
                    completion(.failure(.insufficientFunds))
                }
                return
            }
            
            // Process the transfer
            fromAccount.balance -= request.amount
            fromAccount.lastUpdated = Date()
            toAccount.balance += request.amount
            toAccount.lastUpdated = Date()
            
            let transaction = Transaction(
                id: UUID().uuidString,
                accountId: request.fromAccountId,
                type: .transfer,
                amount: request.amount,
                currency: request.currency,
                description: request.description,
                merchantName: nil,
                category: .transfer,
                status: .completed,
                timestamp: Date(),
                referenceNumber: self.generateReferenceNumber(),
                fromAccountId: request.fromAccountId,
                toAccountId: request.toAccountId,
                metadata: ["initiated_by": "user"]
            )
            
            do {
                // Save updated accounts
                try self.secureStorage.save(fromAccount, forKey: "account_\(fromAccount.id)")
                try self.secureStorage.save(toAccount, forKey: "account_\(toAccount.id)")
                
                // Save transaction
                var transactions = (try? self.secureStorage.load(forKey: "transactions", type: [Transaction].self)) ?? []
                transactions.insert(transaction, at: 0)
                try self.secureStorage.save(transactions, forKey: "transactions")
                
                // Save to recent transactions for duplicate detection
                self.recordRecentTransaction(request: request)
                
                self.auditLogger.log(
                    action: "transfer_completed",
                    details: "Transfer of \(request.amount) \(request.currency) from \(fromAccount.maskedAccountNumber) to \(toAccount.maskedAccountNumber). Ref: \(transaction.referenceNumber)",
                    riskLevel: "normal"
                )
                
                DispatchQueue.main.async {
                    completion(.success(transaction))
                }
            } catch {
                self.auditLogger.log(
                    action: "transfer_failed",
                    details: "Error saving transaction: \(error.localizedDescription)",
                    riskLevel: "elevated"
                )
                DispatchQueue.main.async {
                    completion(.failure(.processingError(error.localizedDescription)))
                }
            }
        }
    }
    
    // MARK: - Duplicate Detection
    
    private func isDuplicateTransaction(request: TransferRequest) -> Bool {
        guard let recentTransactions = try? secureStorage.load(forKey: "recent_transfers", type: [RecentTransfer].self) else {
            return false
        }
        
        let fiveMinutesAgo = Date().addingTimeInterval(-300)
        
        return recentTransactions.contains { recent in
            recent.fromAccountId == request.fromAccountId &&
            recent.toAccountId == request.toAccountId &&
            recent.amount == request.amount &&
            recent.timestamp > fiveMinutesAgo
        }
    }
    
    private func recordRecentTransaction(request: TransferRequest) {
        var recent = (try? secureStorage.load(forKey: "recent_transfers", type: [RecentTransfer].self)) ?? []
        
        recent.append(RecentTransfer(
            fromAccountId: request.fromAccountId,
            toAccountId: request.toAccountId,
            amount: request.amount,
            timestamp: Date()
        ))
        
        // Keep only last hour of transfers
        let oneHourAgo = Date().addingTimeInterval(-3600)
        recent = recent.filter { $0.timestamp > oneHourAgo }
        
        try? secureStorage.save(recent, forKey: "recent_transfers")
    }
    
    private func generateReferenceNumber() -> String {
        let timestamp = Int(Date().timeIntervalSince1970)
        let random = Int.random(in: 100000...999999)
        return "TXN\(timestamp)\(random)"
    }
    
    struct RecentTransfer: Codable {
        let fromAccountId: String
        let toAccountId: String
        let amount: Decimal
        let timestamp: Date
    }
}

// MARK: - Rate Limiter

final class RateLimiter {
    private let maxRequests: Int
    private let timeWindow: TimeInterval
    private var requestTimestamps: [Date] = []
    private let lock = NSLock()
    
    init(maxRequests: Int, timeWindow: TimeInterval) {
        self.maxRequests = maxRequests
        self.timeWindow = timeWindow
    }
    
    func allowRequest() -> Bool {
        lock.lock()
        defer { lock.unlock() }
        
        let now = Date()
        let windowStart = now.addingTimeInterval(-timeWindow)
        
        requestTimestamps = requestTimestamps.filter { $0 > windowStart }
        
        if requestTimestamps.count < maxRequests {
            requestTimestamps.append(now)
            return true
        }
        
        return false
    }
}

// MARK: - Account Manager

final class AccountManager: ObservableObject {
    
    static let shared = AccountManager()
    
    @Published var accounts: [Account] = []
    @Published var transactions: [Transaction] = []
    @Published var isLoading = false
    @Published var errorMessage: String?
    @Published var isAuthenticated = false
    @Published var deviceCompromised = false
    
    private let secureStorage = SecureStorage.shared
    private let auditLogger = AuditLogger.shared
    private let transactionProcessor = TransactionProcessor.shared
    private let biometricAuth = BiometricAuthService.shared
    
    private init() {
        checkDeviceIntegrity()
    }
    
    // MARK: - Device Integrity
    
    func checkDeviceIntegrity() {
        let result = DeviceIntegrityChecker.shared.performFullIntegrityCheck()
        
        DispatchQueue.main.async { [weak self] in
            self?.deviceCompromised = result.isCompromised
        }
        
        if result.isCompromised {
            auditLogger.log(
                action: "device_integrity_warning",
                details: "Threats detected: \(result.threats.map { $0.rawValue }.joined(separator: ", ")). Risk: \(result.riskLevel)",
                riskLevel: "critical"
            )
        }
    }
    
    // MARK: - Authentication
    
    func authenticateWithBiometrics(completion: @escaping (Bool) -> Void) {
        biometricAuth.authenticate(reason: "Authenticate to access your banking app") { [weak self] result in
            switch result {
            case .success:
                self?.isAuthenticated = true
                self?.loadAccounts()
                self?.loadTransactions()
                completion(true)
            case .failure(let error):
                self?.errorMessage = error.localizedDescription
                completion(false)
            }
        }
    }
    
    // MARK: - Account Operations
    
    func loadAccounts() {
        isLoading = true
        
        DispatchQueue.global(qos: .userInitiated).async { [weak self] in
            guard let self = self else { return }
            
            let loadedAccounts: [Account]
            if let stored = try? self.secureStorage.load(forKey: "all_accounts", type: [Account].self) {
                loadedAccounts = stored
            } else {
                // Create demo accounts for first launch
                loadedAccounts = self.createDemoAccounts()
                try? self.secureStorage.save(loadedAccounts, forKey: "all_accounts")
                for account in loadedAccounts {
                    try? self.secureStorage.save(account, forKey: "account_\(account.id)")
                }
            }
            
            DispatchQueue.main.async {
                self.accounts = loadedAccounts
                self.isLoading = false
            }
        }
    }
    
    func loadTransactions() {
        DispatchQueue.global(qos: .userInitiated).async { [weak self] in
            guard let self = self else { return }
            
            let loadedTransactions: [Transaction]
            if let stored = try? self.secureStorage.load(forKey: "transactions", type: [Transaction].self) {
                loadedTransactions = stored
            } else {
                loadedTransactions = self.createDemoTransactions()
                try? self.secureStorage.save(loadedTransactions, forKey: "transactions")
            }
            
            DispatchQueue.main.async {
                self.transactions = loadedTransactions
            }
        }
    }
    
    func getBalance(for accountId: String) -> Decimal {
        return accounts.first(where: { $0.id == accountId })?.balance ?? 0
    }
    
    func getTotalBalance() -> Decimal {
        return accounts.reduce(Decimal.zero) { $0 + $1.balance }
    }
    
    var formattedTotalBalance: String {
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        formatter.currencyCode = "USD"
        return formatter.string(from: getTotalBalance() as NSDecimalNumber) ?? "$0.00"
    }
    
    func getTransactions(for accountId: String) -> [Transaction] {
        return transactions.filter { $0.accountId == accountId }
    }
    
    // MARK: - Transfer
    
    func initiateTransfer(
        from fromAccountId: String,
        to toAccountId: String,
        amount: Decimal,
        description: String,
        completion: @escaping (Result<Transaction, TransactionProcessor.TransactionError>) -> Void
    ) {
        guard isAuthenticated else {
            completion(.failure(.authenticationRequired))
            return
        }
        
        let request = TransferRequest(
            fromAccountId: fromAccountId,
            toAccountId: toAccountId,
            amount: amount,
            currency: "USD",
            description: description,
            scheduledDate: nil
        )
        
        // For amounts > $1000, require biometric re-authentication
        if amount > 1000 {
            biometricAuth.authenticate(reason: "Authenticate to confirm transfer of \(amount)") { [weak self] result in
                switch result {
                case .success:
                    self?.transactionProcessor.processTransfer(request: request, authenticated: true) { [weak self] txResult in
                        if case .success = txResult {
                            self?.loadAccounts()
                            self?.loadTransactions()
                        }
                        completion(txResult)
                    }
                case .failure:
                    completion(.failure(.authenticationRequired))
                }
            }
        } else {
            transactionProcessor.processTransfer(request: request, authenticated: true) { [weak self] txResult in
                if case .success = txResult {
                    self?.loadAccounts()
                    self?.loadTransactions()
                }
                completion(txResult)
            }
        }
    }
    
    // MARK: - Session Management
    
    func logout() {
        isAuthenticated = false
        accounts = []
        transactions = []
        auditLogger.log(action: "logout", details: "User logged out")
        auditLogger.flushLogs()
    }
    
    // MARK: - Demo Data
    
    private func createDemoAccounts() -> [Account] {
        return [
            Account(
                id: "acc_001",
                accountNumber: "1234567890",
                accountType: .checking,
                balance: 5432.10,
                currency: "USD",
                ownerName: "John Doe",
                createdAt: Date().addingTimeInterval(-365 * 24 * 3600),
