// MARK: - UI Components

import SwiftUI

struct SecurityWarningBanner: View {
    let threats: [DeviceIntegrityChecker.ThreatType]
    
    var body: some View {
        VStack(alignment: .leading, spacing: 8) {
            HStack {
                Image(systemName: "exclamationmark.shield.fill")
                    .foregroundColor(.white)
                    .font(.title2)
                Text("Security Warning")
                    .font(.headline)
                    .foregroundColor(.white)
                    .bold()
            }
            
            Text("Your device may be compromised. Some features are restricted for your protection.")
                .font(.caption)
                .foregroundColor(.white.opacity(0.9))
            
            ForEach(threats, id: \.rawValue) { threat in
                HStack(spacing: 4) {
                    Image(systemName: "xmark.circle.fill")
                        .font(.caption2)
                    Text(threat.rawValue)
                        .font(.caption2)
                }
                .foregroundColor(.white.opacity(0.8))
            }
        }
        .padding()
        .background(
            RoundedRectangle(cornerRadius: 12)
                .fill(Color.red.gradient)
        )
        .padding(.horizontal)
    }
}

struct AccountCardView: View {
    let account: Account
    
    var body: some View {
        VStack(alignment: .leading, spacing: 12) {
            HStack {
                VStack(alignment: .leading, spacing: 4) {
                    Text(account.accountType.rawValue)
                        .font(.subheadline)
                        .foregroundColor(.white.opacity(0.8))
                    Text(account.maskedAccountNumber)
                        .font(.caption)
                        .foregroundColor(.white.opacity(0.6))
                }
                Spacer()
                Image(systemName: accountIcon)
                    .font(.title2)
                    .foregroundColor(.white.opacity(0.8))
            }
            
            Spacer()
            
            Text(account.formattedBalance)
                .font(.system(size: 28, weight: .bold, design: .rounded))
                .foregroundColor(.white)
            
            Text("Available Balance")
                .font(.caption)
                .foregroundColor(.white.opacity(0.7))
        }
        .padding(20)
        .frame(height: 160)
        .background(
            RoundedRectangle(cornerRadius: 16)
                .fill(cardGradient)
        )
        .shadow(color: .black.opacity(0.15), radius: 10, x: 0, y: 5)
    }
    
    private var accountIcon: String {
        switch account.accountType {
        case .checking: return "banknote"
        case .savings: return "building.columns"
        case .credit